 64→        if (announcement != null) {
 65→            announcement.setTitle(ro.getTitle());
 66→            announcement.setContent(ro.getContent());
 67→            announcement.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
 68→            announcement.setType(AnnouncementType.TIMED.getCode());
 69→            announcement.setStatus(AnnouncementStatus.WAITING.getCode());
 70→            isUpdate = true;
 71→        }
 72→        else {
 73→            // 不存在则新建
 74→            announcement = createNewAnnouncement(ro);
 75→            log.info("指定的公告ID不存在，将创建新公告");
 76→        }
 77→
 78→
 79→        // 2. 判断发布时间并设置状态
 80→        LocalDateTime currentTime = LocalDateTime.now();
 81→        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
 82→        LocalDateTime publishTime = LocalDateTime.parse(ro.getPublishTime(), formatter);
 83→        String operationMessage;
 84→
 85→        if (publishTime.isBefore(currentTime) || publishTime.isEqual(currentTime)) {
 86→            // 即刻发布
 87→            announcement.setPublishTime(publishTime);
 88→            operationMessage = isUpdate ? "公告更新并即刻发布成功" : "公告创建并即刻发布成功";
 89→            log.info("公告将即刻发布，ID：{}", announcement.getId());
 90→
 91→        } else {
 92→            // 定时发布
 93→            announcement.setPublishTime(publishTime);
 94→            operationMessage = isUpdate ? "公告更新并设置定时发布成功" : "公告创建并设置定时发布成功";
 95→            log.info("公告将定时发布，ID：{}，发布时间：{}", announcement.getId(), publishTime);
 96→        }
 97→
 98→        if (isUpdate) {
 99→            announcementMapper.updateById(announcement) ;
100→        }
101→        else{
102→            announcementMapper.insert(announcement);
103→        }
104→
105→
106→        // 3. 如果是定时发布，添加到延迟队列
107→        if (announcement.getType() == AnnouncementType.TIMED.getCode() && publishTime.isAfter(currentTime)) {
108→            try {
109→                // 使用RabbitMq延迟队列
110→                long delay = Duration.between(LocalDateTime.now(), publishTime).toMillis();
111→                log.info("延时时间，公告ID：{}，发布时间：{}", announcement.getId(), delay);
112→                Message message = new Message(announcement.getId().toString().getBytes());
113→                rabbitMqSender.sendDelayedMessage(QueueConfig.ANNOUNCEMENT_EXCHANGE, QueueConfig.ANNOUNCEMENT_KEY, message, delay);
114→
115→                log.info("已添加定时发布任务，公告ID：{}，发布时间：{}", announcement.getId(), publishTime);
116→            } catch (Exception e) {
117→                log.error("添加定时发布任务失败，公告ID：{}", announcement.getId(), e);
118→                // 改成公告
119→                announcement.setStatus(AnnouncementType.DRAFT.getCode());
120→                operationMessage += "（定时任务创建失败，发布内容已存储到草稿）";
121→            }
122→        }
123→
124→        // 4. 构建返回对象
125→        CreateAnnouncementVo result = new CreateAnnouncementVo();
126→        result.setId(announcement.getId());
127→        result.setTitle(announcement.getTitle());
128→        result.setContent(announcement.getContent());
129→        result.setPublishTime(announcement.getPublishTime());
130→        result.setMessage(operationMessage);
131→
132→        log.info("公告创建/更新完成，返回结果：{}", result);
133→        return result;
134→    }
